import React, { useState } from 'react';
import AdminDashboard from './components/Admin/AdminDashboard';
import UserSite from './components/User/UserSite';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'admin' | 'user'>('admin');

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <h1 className="text-xl font-bold text-gray-900">Land Records Management</h1>
            </div>
            <div className="flex items-center space-x-4">
              <button
                onClick={() => setCurrentView('admin')}
                className={`px-4 py-2 rounded-md text-sm font-medium ${
                  currentView === 'admin'
                    ? 'bg-blue-600 text-white'
                    : 'text-gray-700 hover:bg-gray-100'
                }`}
              >
                Admin Dashboard
              </button>
              <button
                onClick={() => setCurrentView('user')}
                className={`px-4 py-2 rounded-md text-sm font-medium ${
                  currentView === 'user'
                    ? 'bg-blue-600 text-white'
                    : 'text-gray-700 hover:bg-gray-100'
                }`}
              >
                User Site
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        {currentView === 'admin' ? <AdminDashboard /> : <UserSite />}
      </main>
    </div>
  );
};

export default App;
